                    {t("common.edit")}
                  </button>
                  <button
                    onClick={() => handleDelete(req.id)}
                    className="text-red-600 hover:underline"
                  >
                    {t("common.delete")}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

