              <input
                name="title"
                value={formData.title}
                onChange={handleInputChange}
                placeholder={t("community.form.titlePlaceholder")}
                className="w-full p-2 border rounded text-sm"
                required
              />
              <textarea
                name="content"
                value={formData.content}
                onChange={handleInputChange}
                rows="3"
                placeholder={t("community.form.contentPlaceholder")}
                className="w-full p-2 border rounded text-sm"
                required
              ></textarea>
              <div className="flex gap-2">
                <button
                  type="submit"
                  className="w-full bg-teal-600 text-white p-2 rounded text-sm hover:bg-teal-700"
                >
                  {t("community.actions.publish")}
                </button>
                <button
                  type="button"
                  onClick={() => setIsFormVisible(false)}
                  className="w-full bg-gray-300 text-gray-800 p-2 rounded text-sm hover:bg-gray-400"
                >
                  {t("common.cancel")}
                </button>
              </div>
            </form>
          )}

          <div className="flex-grow overflow-y-auto space-y-2">
            <h4 className="font-semibold mb-2">{t("community.list.title")}</h4>
            {isLoading && <p className="text-center">{t("common.loading")}</p>}
            {error && <p className="text-center text-red-500">{error}</p>}
            {!isLoading &&
              !error &&
              posts.map((post) => (
                <div
                  key={post.id}
                  onClick={() => openPostModal(post)}
                  className="bg-white p-3 rounded-lg shadow cursor-pointer"
                >
                  <div className="flex justify-between items-start">
                    <span className="text-xs bg-sky-100 text-sky-800 px-2 py-1 rounded-full font-semibold">
                      {post.category}
                    </span>
                    <span className="text-xs text-gray-400">
                      {new Date(post.created_at).toLocaleDateString()}
                    </span>
                  </div>
                  <p className="font-bold text-sm mt-2 truncate">
                    {post.title}
                  </p>
                  <p className="text-xs text-gray-500 mt-1">
                    {t("community.list.author")}: {post.author_name}
                  </p>
                </div>
              ))}
          </div>
        </div>
      </PhoneMockup>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={selectedPost?.title}
      >
        <div className="space-y-4">
          <div className="text-sm text-gray-500">
            <span>
              {t("community.list.category")}: {selectedPost?.category}
            </span>{" "}
            |{" "}
            <span>
              {t("community.list.author")}: {selectedPost?.author_name}
            </span>
          </div>
          <p className="text-gray-700 whitespace-pre-wrap">
            {selectedPost?.content}
          </p>
        </div>
      </Modal>
    </>
  );
};
export default CommunityScreen;

import React, { useState, useEffect } from "react";
import { useAppContext } from "../../contexts/AppContext";
import { useTranslation } from "react-i18next";
import PhoneMockup from "../../components/common/PhoneMockup";
import HomeButton from "../../components/common/HomeButton";
import Loader from "../../components/common/Loader";
import ErrorAlert from "../../components/common/ErrorAlert";

const MaintenanceScreen = () => {
  const { showToast, fetchWithAuth } = useAppContext();
  const { t } = useTranslation();
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [isFormVisible, setIsFormVisible] = useState(false);
  const [formData, setFormData] = useState({
    category: "Plomería",
    description: "",
  });

  // Al cargar el componente, se obtiene la lista de solicitudes desde la API
  const fetchRequests = async () => {
    setLoading(true);
    setError("");
    try {
      const response = await fetchWithAuth("/resident/tasks");
      if (!response.ok) throw new Error(t("maintenance.errors.loadFailed"));
      const data = await response.json();
      setRequests(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetchWithAuth("/resident/tasks", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });

      if (!response.ok) {
        throw new Error(t("maintenance.errors.createFailed"));
      }

      showToast(t("maintenance.success.received"));
      setIsFormVisible(false);
      setFormData({ category: "Plomería", description: "" });
      fetchRequests(); // Recargar la lista
    } catch (err) {
      showToast(t("common.errorWithMessage", { message: err.message }));
    }
  };

  const statusColor = {
    Recibido: "text-yellow-500",
    "En Proceso": "text-blue-500",
    Completado: "text-green-500",
    "En Espera": "text-gray-500",
  };

  return (
    <PhoneMockup theme="light">
      <div className="relative h-[650px] flex flex-col">
        <HomeButton />
        <h3 className="text-xl font-bold text-center mb-4 flex-shrink-0">
          {t("maintenance.title")}
        </h3>

        {!isFormVisible && (
          <button
            onClick={() => setIsFormVisible(true)}
            className="w-full p-3 rounded-lg bg-teal-600 text-white font-bold hover:bg-teal-700 mb-4"
          >
            {t("maintenance.actions.newReportPlus")}
          </button>
        )}

        {isFormVisible && (
          <form
            onSubmit={handleSubmit}
            className="bg-white p-3 rounded-lg shadow mb-4 space-y-3"
          >
            <h4 className="font-semibold">{t("maintenance.form.newTitle")}</h4>
            <div>
              <label className="text-xs font-medium">
                {t("maintenance.form.typeLabel")}
              </label>
              <select
                name="category"
                value={formData.category}
                onChange={handleInputChange}
                className="w-full p-2 border rounded mt-1 text-sm"
              >
                <option value="Plomería">Plomería</option>
                <option value="Electricidad">Electricidad</option>
                <option value="Instalación">Instalación</option>
                <option value="Otro">Otro</option>
              </select>
            </div>
            <div>
              <label className="text-xs font-medium">
                {t("maintenance.form.detailLabel")}
              </label>
              <textarea
                name="description"
                value={formData.description}
                onChange={handleInputChange}
                rows="3"
                placeholder={t("maintenance.form.detailPlaceholder")}
                className="w-full p-2 border rounded mt-1 text-sm"
                required
              ></textarea>
            </div>
            <div className="flex gap-2">
              <button
                type="submit"
                className="w-full bg-teal-600 text-white p-2 rounded text-sm hover:bg-teal-700"
              >
                {t("maintenance.actions.submit")}
              </button>
              <button
                type="button"
                onClick={() => setIsFormVisible(false)}
                className="w-full bg-gray-300 text-gray-800 p-2 rounded text-sm hover:bg-gray-400"
              >
                {t("common.cancel")}
              </button>
            </div>
          </form>
        )}

        <div className="flex-grow overflow-y-auto space-y-2">
          <h4 className="font-semibold mb-2">{t("maintenance.list.title")}</h4>
          {loading && <Loader message={t("common.loading")} />}
          {error && (
            <div className="px-4">
              <ErrorAlert message={error} />
            </div>
          )}
          {!loading &&
            !error &&
            requests.map((req) => (
              <div key={req.id} className="bg-white p-3 rounded-lg shadow">
                <div className="flex justify-between items-start">
                  <p className="font-bold text-sm">{req.category}</p>
                  <p className={`text-xs font-bold ${statusColor[req.status]}`}>
                    {req.status}
                  </p>
                </div>
                <p className="text-xs text-gray-600 mt-1">{req.description}</p>
                <p className="text-right text-xs text-gray-400 mt-2">
                  {new Date(req.created_at).toLocaleDateString()}
                </p>
              </div>
            ))}
        </div>
      </div>
    </PhoneMockup>
  );
};

export default MaintenanceScreen;

import React, { useState, useEffect } from "react";
import { useAppContext } from "../../contexts/AppContext";
import { useTranslation } from "react-i18next";
import PhoneMockup from "../../components/common/PhoneMockup";
import Modal from "../../components/common/Modal";
import HomeButton from "../../components/common/HomeButton";
import Loader from "../../components/common/Loader";
import ErrorAlert from "../../components/common/ErrorAlert";

const PaymentScreen = () => {
  const { showToast, fetchWithAuth } = useAppContext();
  const { t } = useTranslation();
  const [bills, setBills] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [detailOpen, setDetailOpen] = useState(false);
  const [currentBill, setCurrentBill] = useState(null);

  useEffect(() => {
    const load = async () => {
      try {
        setLoading(true);
        setError("");
        const res = await fetchWithAuth("/resident/payments/bills");
        if (!res.ok) {
          const data = await res.json().catch(() => ({}));
          throw new Error(data.message || t("payment.errors.loadBillsFailed"));
        }
        const data = await res.json();
        setBills(data);
      } catch (e) {
        setError(e.message);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [fetchWithAuth]);

  const openDetail = (bill) => {
    setCurrentBill(bill);
    setDetailOpen(true);
  };

  const payMock = () => {
    if (!currentBill) return;
    // Mock: 변경만 UI에 반영
    setBills((prev) =>
      prev.map((b) =>
        b.id === currentBill.id ? { ...b, status: "Pagado" } : b,
      ),
    );
    setCurrentBill({ ...currentBill, status: "Pagado" });
    setDetailOpen(false);
    showToast(t("payment.success.mockPaid"));
  };

  const downloadReceipt = (bill) => {
    const b = bill || currentBill;
    if (!b) return;
    const html = `<!doctype html><html><head><meta charset="utf-8"><style>
      body{font-family:Arial;padding:20px}h2{margin:0 0 10px}table{width:100%;border-collapse:collapse;margin-top:10px}
      th,td{border:1px solid #ddd;padding:6px;text-align:right}th{text-align:left;background:#f3f4f6}
    </style></head><body>
      <h2>영수증 (샘플)</h2>
      <p>청구월: ${b.bill_month}</p>
      <p>상태: ${b.status}</p>
      <table><thead><tr><th>항목</th><th>금액</th></tr></thead><tbody>
        ${(b.items || []).map((it) => `<tr><td style="text-align:left">${it.item_name}</td><td>${Number(it.amount || 0).toLocaleString()}</td></tr>`).join("")}
        <tr><td style="text-align:left"><strong>합계</strong></td><td><strong>${Number(b.total_amount || 0).toLocaleString()}</strong></td></tr>
      </tbody></table>
      <script>window.onload=function(){window.print();window.close();}</script>
    </body></html>`;
    const w = window.open("", "receipt");
    if (!w) return;
    w.document.open();
    w.document.write(html);
    w.document.close();
  };

  if (loading)
    return (
      <PhoneMockup theme="light">
        <Loader message={t("payment.loadingBills")} />
      </PhoneMockup>
    );
  if (error)
    return (
      <PhoneMockup theme="light">
        <div className="p-6">
          <ErrorAlert
            message={t("common.errorWithMessage", { message: error })}
          />
        </div>
      </PhoneMockup>
    );

  // Group by month
  const months = Array.from(new Set(bills.map((b) => b.bill_month)))
    .sort()
    .reverse();

  return (
    <>
      <PhoneMockup theme="light">
        <div className="relative h-full flex flex-col">
          <HomeButton />
          <h3 className="text-xl font-bold text-center mb-4">
            {t("payment.title")}
          </h3>
          <div className="space-y-4 overflow-y-auto flex-grow">
            {months.map((m) => (
              <div key={m} className="bg-white rounded-lg shadow p-3">
                <div className="flex justify-between items-center mb-2">
                  <div className="font-bold">{m}</div>
                </div>
                {bills
                  .filter((b) => b.bill_month === m)
                  .map((bill) => (
                    <div
                      key={bill.id}
                      className="flex justify-between items-center border-t py-2"
                    >
                      <div>
                        <div className="text-sm text-gray-600">
                          {t("payment.due")}: {bill.due_date}
                        </div>
                        <div
                          className={`text-xs font-semibold ${bill.status === "Pendiente" ? "text-red-600" : "text-green-600"}`}
                        >
                          {bill.status}
                        </div>
                      </div>
                      <div className="text-right">
                        <div className="font-bold">
                          {Number(bill.total_amount || 0).toLocaleString()} $
                        </div>
                        <div className="mt-1 flex gap-2 justify-end">
                          <button
                            onClick={() => openDetail(bill)}
                            className="px-2 py-1 text-xs rounded bg-gray-200 hover:bg-gray-300"
                          >
                            {t("payment.actions.detail")}
                          </button>
                          {bill.status !== "Pendiente" && (
                            <button
                              onClick={() => downloadReceipt(bill)}
                              className="px-2 py-1 text-xs rounded bg-sky-600 text-white hover:bg-sky-700"
                            >
                              {t("payment.actions.receipt")}
                            </button>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
              </div>
            ))}
          </div>
        </div>
      </PhoneMockup>

      <Modal
        isOpen={detailOpen}
        onClose={() => setDetailOpen(false)}
        title={t("payment.detailTitle")}
      >
        {currentBill && (
          <div>
            <div className="flex justify-between mb-2 text-sm">
              <div>
                {t("payment.table.month")}: {currentBill.bill_month}
              </div>
              <div>
                {t("payment.table.status")}:{" "}
                <span
                  className={
                    currentBill.status === "Pendiente"
                      ? "text-red-600"
                      : "text-green-600"
                  }
                >
                  {currentBill.status}
                </span>
              </div>
            </div>
            <div className="border rounded overflow-hidden">
              <table className="w-full text-sm">
                <thead className="bg-gray-100">
                  <tr>
                    <th className="p-2 text-left">{t("payment.table.item")}</th>
                    <th className="p-2 text-right">
                      {t("payment.table.amount")}
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {(currentBill.items || []).map((it, idx) => (
                    <tr key={idx} className="border-t">
                      <td className="p-2">{it.item_name}</td>
                      <td className="p-2 text-right">
                        {Number(it.amount || 0).toLocaleString()}
                      </td>
                    </tr>
                  ))}
                  <tr className="border-t font-semibold">
                    <td className="p-2">{t("payment.table.total")}</td>
                    <td className="p-2 text-right">
                      {Number(currentBill.total_amount || 0).toLocaleString()}
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
            {currentBill.status === "Pendiente" ? (
              <button
                onClick={payMock}
                className="w-full mt-3 p-2 rounded bg-teal-600 text-white hover:bg-teal-700 font-bold"
              >
                {t("payment.actions.mockPay")}
              </button>
            ) : (
              <button
                onClick={() => downloadReceipt()}
                className="w-full mt-3 p-2 rounded bg-sky-600 text-white hover:bg-sky-700 font-bold"
              >
                {t("payment.actions.receiptPdf")}
              </button>
            )}
          </div>
        )}
      </Modal>
    </>
  );
};

export default PaymentScreen;

import React, { useState, useEffect, useMemo } from "react";
import { useAppContext } from "../../contexts/AppContext";
import { useTranslation } from "react-i18next";
import PhoneMockup from "../../components/common/PhoneMockup";
import Modal from "../../components/common/Modal";
import HomeButton from "../../components/common/HomeButton";
import Loader from "../../components/common/Loader";
import ErrorAlert from "../../components/common/ErrorAlert";

const ReservationScreen = () => {
  const { showToast, fetchWithAuth } = useAppContext();
  const { t } = useTranslation();
  const [facilities, setFacilities] = useState([]);
  const [reservations, setReservations] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedFacility, setSelectedFacility] = useState(null);
  const [reservationDate, setReservationDate] = useState(() =>
    new Date().toISOString().slice(0, 10),
  );
  const [reservationTime, setReservationTime] = useState("10:00-12:00");

  const fetchAllData = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [facilitiesRes, reservationsRes] = await Promise.all([
        fetchWithAuth("/resident/reservations/facilities"),
        fetchWithAuth("/resident/reservations"),
      ]);
      if (!facilitiesRes.ok || !reservationsRes.ok) {
        throw new Error(t("reservation.errors.loadFailed"));
      }
      const facilitiesData = await facilitiesRes.json();
      const reservationsData = await reservationsRes.json();
      setFacilities(facilitiesData);
      setReservations(reservationsData);
    } catch (err) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchAllData();
  }, []);

  const handleReserveClick = (facility) => {
    setSelectedFacility(facility);
    setIsModalOpen(true);
  };

  const handleConfirmReservation = async () => {
    if (!reservationDate) {
      showToast(t("reservation.errors.selectDate"));
      return;
    }

    const [startTime, endTime] = reservationTime.split("-");
    const startDateTime = `${reservationDate}T${startTime.trim()}`;
    const endDateTime = `${reservationDate}T${endTime.trim()}`;

    try {
      const response = await fetchWithAuth("/resident/reservations", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          facilityId: selectedFacility.id,
          startTime: startDateTime,
          endTime: endDateTime,
        }),
      });
      if (!response.ok) throw new Error(t("reservation.errors.createFailed"));

      setIsModalOpen(false);
      showToast(
        t("reservation.success.requested", { name: selectedFacility.name }),
      );
      fetchAllData(); // Recargar datos
    } catch (err) {
      showToast(t("common.errorWithMessage", { message: err.message }));
    }
  };

  const handleCancelReservation = async (reservationId) => {
    if (!window.confirm(t("reservation.confirmCancel"))) return;

    try {
      const response = await fetchWithAuth(
        `/resident/reservations/${reservationId}`,
        {
          method: "DELETE",
        },
      );
      if (!response.ok) throw new Error(t("reservation.errors.cancelFailed"));

      showToast(t("reservation.success.canceled"));
      fetchAllData(); // Recargar datos
    } catch (err) {
      showToast(t("common.errorWithMessage", { message: err.message }));
    }
  };

  const statusColor = {
    Aprobada: "text-green-500",
    Pendiente: "text-yellow-500",
    Rechazada: "text-red-500",
    Cancelada: "text-gray-500",
  };

  const slots = useMemo(
    () => [
      "08:00-10:00",
      "10:00-12:00",
      "12:00-14:00",
      "14:00-16:00",
      "16:00-18:00",
      "18:00-20:00",
    ],
    [],
  );

  const dayReservations = useMemo(() => {
    if (!selectedFacility) return [];
    const dayStr = reservationDate;
    return reservations.filter(
      (r) =>
        r.facility_name === selectedFacility.name &&
        r.start_time?.slice(0, 10) === dayStr,
    );
  }, [reservations, selectedFacility, reservationDate]);

  const occupied = new Set(
    dayReservations.map(
      (r) =>
        `${new Date(r.start_time).toTimeString().slice(0, 5)}-${new Date(r.end_time).toTimeString().slice(0, 5)}`,
    ),
  );

  if (isLoading)
    return (
      <PhoneMockup theme="light">
        <Loader message={t("common.loading")} />
      </PhoneMockup>
    );
  if (error)
    return (
      <PhoneMockup theme="light">
        <div className="p-6">
          <ErrorAlert
            message={t("common.errorWithMessage", { message: error })}
          />
        </div>
      </PhoneMockup>
    );

  return (
    <>
      <PhoneMockup theme="light">
        <div className="relative h-[650px] flex flex-col">
          <HomeButton />
          <h3 className="text-xl font-bold text-center mb-4 flex-shrink-0">
            {t("reservation.title")}
          </h3>
          <div className="flex-grow overflow-y-auto space-y-4">
            <div>
              <h4 className="font-semibold mb-2">
                {t("reservation.availableFacilities")}
              </h4>
              <div className="space-y-2">
                {facilities.map((f) => (
                  <div key={f.id} className="bg-white p-3 rounded-lg shadow">
                    <p className="font-bold">{f.name}</p>
                    <p className="text-xs text-gray-500 mt-1">
                      {f.description}
                    </p>
                    <button
                      onClick={() => handleReserveClick(f)}
                      className="w-full mt-2 text-sm p-2 rounded bg-teal-600 text-white hover:bg-teal-700"
                    >
                      {t("reservation.actions.reserve")}
                    </button>
                  </div>
                ))}
              </div>
            </div>
            <div>
              <h4 className="font-semibold mb-2">
                {t("reservation.myReservations")}
              </h4>
              <div className="space-y-2">
                {reservations.map((r) => (
                  <div key={r.id} className="bg-white p-3 rounded-lg shadow">
                    <div className="flex justify-between items-start">
                      <div>
                        <p className="font-bold">{r.facility_name}</p>
                        <p className="text-xs text-gray-500">
                          {new Date(r.start_time).toLocaleString()} ~{" "}
                          {new Date(r.end_time).toLocaleTimeString()}
                        </p>
                      </div>
                      <p
                        className={`text-xs font-bold ${statusColor[r.status]}`}
                      >
                        {r.status}
                      </p>
                    </div>
                    {(r.status === "Pendiente" || r.status === "Aprobada") && (
                      <button
                        onClick={() => handleCancelReservation(r.id)}
                        className="w-full mt-2 text-xs p-1 rounded bg-red-500 text-white hover:bg-red-600"
                      >
                        {t("reservation.actions.cancel")}
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </PhoneMockup>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={t("reservation.modal.title", {
          name: selectedFacility?.name || "",
        })}
      >
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700">
              {t("reservation.modal.selectDate")}
            </label>
            <input
              type="date"
              value={reservationDate}
              onChange={(e) => setReservationDate(e.target.value)}
              className="w-full p-2 border rounded mt-1"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700">
              {t("reservation.modal.selectTime")}
            </label>
            <div className="grid grid-cols-2 gap-2 mt-1">
              {slots.map((s) => {
                const disabled = occupied.has(s);
                return (
                  <button
                    key={s}
                    type="button"
                    onClick={() => !disabled && setReservationTime(s)}
                    className={`p-2 rounded text-sm border ${reservationTime === s ? "bg-teal-600 text-white" : "bg-white"} ${disabled ? "opacity-50 cursor-not-allowed border-gray-200" : "hover:bg-gray-50"}`}
                  >
                    {s} {disabled && `(${t("reservation.modal.unavailable")})`}
                  </button>
                );
              })}
            </div>
            <p className="text-xs text-gray-500 mt-1">
              {t("reservation.modal.availabilityNote")}
            </p>
          </div>
          <button
            onClick={handleConfirmReservation}
            className="w-full p-2 rounded bg-teal-600 text-white hover:bg-teal-700"
          >
            {t("reservation.actions.request")}
          </button>
        </div>
      </Modal>
    </>
  );
};
export default ReservationScreen;
